import { UI, color } from "./index.js";
import { Message } from "../types/types.js";

const print = (m: any, cil: any) => {
  if (!cil.config.showLogs) return 
  if (Array.isArray(m)) {
    m = m[0];
  }
  
  if (!m || !m.key) {
    UI.warn('Invalid message object received');
    return;
  }

  const sender = m.pushName || 'Unknown';
  const remoteJid = m.key.remoteJid || 'N/A';
  const timestamp = m.messageTimestamp ? new Date(m.messageTimestamp * 1000).toLocaleString() : 'Unknown';
  const chatType = remoteJid.includes('@g.us') ? '👥 Group' : '👤 Private';
  
  let messageType = 'Unknown';
  let messageContent = '';
  
  if (m.message) {
    if (m.message.conversation) {
      messageType = 'Text';
      messageContent = m.message.conversation;
    } else if (m.message.imageMessage) {
      messageType = 'Image';
      messageContent = m.message.imageMessage.caption || 'No caption';
    } else if (m.message.videoMessage) {
      messageType = 'Video';
      messageContent = m.message.videoMessage.caption || 'No caption';
    } else if (m.message.stickerMessage) {
      messageType = 'Sticker';
      messageContent = '🧩 Sticker';
    } else if (m.message.documentMessage) {
      messageType = 'Document';
      messageContent = m.message.documentMessage.title || 'Document';
    } else if (m.message.audioMessage) {
      messageType = 'Audio';
      messageContent = m.message.audioMessage.seconds ? `${m.message.audioMessage.seconds}s` : 'Audio';
    } else if (m.message.contactMessage) {
      messageType = 'Contact';
      messageContent = m.message.contactMessage.displayName || 'Contact';
    } else if (m.message.locationMessage) {
      messageType = 'Location';
      messageContent = '📍 Location';
    } else if (m.message.reactionMessage) {
      messageType = 'Reaction';
      messageContent = m.message.reactionMessage.text || '👍';
    } else if (m.message.extendedTextMessage) {
      messageType = 'Extended Text';
      messageContent = m.message.extendedTextMessage.text || '';
    } else if (m.message.protocolMessage) {
      messageType = 'Protocol';
      messageContent = 'Protocol message';
    } else {
      messageType = 'Other';
      messageContent = 'Complex message type';
    }
  }

  console.log('╭─┈─ ' + color("Message status", "yellow") + '⌢̶᷼─ᐢ᮫ׄ ׅ➛');
  console.log(`⌘ From: ${color(sender, "blue")}`);
  console.log(`⌘ Chat: ${color(remoteJid, "green")}`);
  console.log(`⌘ Type: ${color(chatType, "yellow")}`);
  console.log(`⌘ Time: ${color(timestamp, "magenta")}`);
  console.log(`⌘ Message Type: ${color(messageType, "cyan")}`);
  console.log('╰═⵿͡─┈─┈─ > 𓈑');
  console.log(`╭─┈─ ${color("Message Content", "magenta")} ⌢̶᷼─ᐢ᮫ׄ ׅ➛
✦ Content: ${color(messageContent, "yellow")}
╰═⵿͡─┈─┈─ > 𔒱` + "\n");
};

export { print }