type EndpointConfig = {
  title: string;
  method: 'GET' | 'POST' | 'PUT' | 'DELETE';
  query: readonly string[];
  path: string;
};

function createApiCaller(endpoint: EndpointConfig) {
  return async (params: Record<string, string>) => {
    try {
      for (const key of endpoint.query) {
        if (!params[key]) {
          throw new Error(`Missing required parameter: ${key}`);
        }
      }

      const response = await apiClient.request({
        method: endpoint.method,
        url: endpoint.path,
        params: params
      });
      
      return response.data;
    } catch (error: any) {
      console.error(`Error in ${endpoint.title}:`, error.message);
      throw error;
    }
  };
}

function createScrapy() {
  const scrapy: any = {
    test: async (url: string) => {
      try {
        const res = await fetch(url);
        return res.text();
      } catch {
        return false;
      }
    },
    download: {}
  };

  for (const [category, endpoints] of Object.entries(downloadEndpoints)) {
    scrapy.download[category] = {};
    
    for (const [name, config] of Object.entries(endpoints)) {
      scrapy.download[category][name] = createApiCaller(config as EndpointConfig);
    }
  }

  return scrapy;
}

export const scrapy = createScrapy();