import { readdir, readFile } from 'fs/promises';
import { pathToFileURL, fileURLToPath } from 'url';
import { createRequire } from 'module';
import { resolve, join, dirname, relative, isAbsolute, parse as parsePath } from 'path';
import { Message, CommandOptions, CommandContext } from "../types/types.js";
import { extractPrefix } from './prefix.js';
import { watch, FSWatcher } from 'chokidar';
import { existsSync } from 'fs';
import { cmdControl } from "../control/index.js";
import { UI } from "../utils/index.js";
import { AsyncLocalStorage } from 'async_hooks';

const __filename = fileURLToPath(import.meta.url);
const __dirname = dirname(__filename);

type Handler = (msg: Message, ctx: any, bot?: any) => Promise<boolean | void>;
type Middleware = (msg: Message, next: () => Promise<void>) => Promise<void>;
type CommandModule = CommandOptions | CommandOptions[] | Handler;

const COMMAND_PROPS = {
  basic: ['command', 'name', 'description', 'aliases', 'category', 'usage'],
  restrictions: ['owner', 'group', 'private', 'botAdmin', 'admin'],
  settings: ['cooldown', 'disabled', 'usePrefix'],
  hooks: ['before', 'after']
};

const ALL_PROPS = [
  ...COMMAND_PROPS.basic,
  ...COMMAND_PROPS.restrictions,
  ...COMMAND_PROPS.settings,
  ...COMMAND_PROPS.hooks
];

const VALID_EXTENSIONS = ['js', 'ts', 'mjs', 'cjs'];

const commandStorage = new AsyncLocalStorage<any>();

class CooldownManager {
  private cache: Map<string, number>;
  private readonly maxAge: number;
  private cleanupInterval: ReturnType<typeof setInterval>;

  constructor(maxAge: number = 3600000) {
    this.cache = new Map();
    this.maxAge = maxAge;
    this.cleanupInterval = setInterval(() => this.cleanup(), 60000);
  }

  set(key: string): void {
    this.cache.set(key, Date.now());
  }

  clear(key?: string): void {
    if (key) {
      this.cache.delete(key);
    } else {
      this.cache.clear();
    }
  }

  getRemaining(key: string, cooldown: number): number {
    const lastUsed = this.cache.get(key);
    if (!lastUsed) return 0;
    const elapsed = (Date.now() - lastUsed) / 1000;
    const remaining = Math.ceil(cooldown - elapsed);
    return remaining > 0 ? remaining : 0;
  }

  private cleanup(): void {
    const now = Date.now();
    for (const [key, time] of this.cache.entries()) {
      if (now - time > this.maxAge) {
        this.cache.delete(key);
      }
    }
  }

  destroy(): void {
    clearInterval(this.cleanupInterval);
    this.cache.clear();
  }
}

class CommandRegistry {
  private commands: Map<string, CommandOptions> = new Map();
  private nameIndex: Map<string, string> = new Map();
  private aliasIndex: Map<string, string> = new Map();
  private categoryIndex: Map<string, Set<string>> = new Map();
  private fileIndex: Map<string, Set<string>> = new Map();
  private beforeHookIndex: Set<string> = new Set();

  register(command: CommandOptions, filePath?: string): string {
    const id = this.generateId(command);
    this.commands.set(id, command);

    const names = this.getCommandNames(command);
    names.forEach(name => {
      this.nameIndex.set(name.toLowerCase(), id);
    });

    if (command.aliases) {
      command.aliases.forEach(alias => {
        this.aliasIndex.set(alias.toLowerCase(), id);
      });
    }

    if (command.category) {
      if (!this.categoryIndex.has(command.category)) {
        this.categoryIndex.set(command.category, new Set());
      }
      this.categoryIndex.get(command.category)!.add(id);
    }

    if (filePath) {
      const normalizedPath = resolve(filePath);
      if (!this.fileIndex.has(normalizedPath)) {
        this.fileIndex.set(normalizedPath, new Set());
      }
      this.fileIndex.get(normalizedPath)!.add(id);
    }

    if (command.before) {
      this.beforeHookIndex.add(id);
    }

    return id;
  }

  findByName(name: string): CommandOptions | undefined {
    const id = this.nameIndex.get(name.toLowerCase()) || this.aliasIndex.get(name.toLowerCase());
    return id ? this.commands.get(id) : undefined;
  }

  findByCategory(category: string): CommandOptions[] {
    const ids = this.categoryIndex.get(category);
    if (!ids) return [];
    return Array.from(ids)
      .map(id => this.commands.get(id))
      .filter((cmd): cmd is CommandOptions => cmd !== undefined);
  }

  findByFile(filePath: string): CommandOptions[] {
    const normalizedPath = resolve(filePath);
    const ids = this.fileIndex.get(normalizedPath);
    if (!ids) return [];
    return Array.from(ids)
      .map(id => this.commands.get(id))
      .filter((cmd): cmd is CommandOptions => cmd !== undefined);
  }

  getCommandsWithBeforeHooks(): CommandOptions[] {
    return Array.from(this.beforeHookIndex)
      .map(id => this.commands.get(id))
      .filter((cmd): cmd is CommandOptions => cmd !== undefined);
  }

  unregister(name: string): boolean {
    const id = this.nameIndex.get(name.toLowerCase());
    if (!id) return false;

    const cmd = this.commands.get(id);
    if (!cmd) return false;

    this.commands.delete(id);
    this.beforeHookIndex.delete(id);

    const names = this.getCommandNames(cmd);
    names.forEach(n => this.nameIndex.delete(n.toLowerCase()));

    if (cmd.aliases) {
      cmd.aliases.forEach(a => this.aliasIndex.delete(a.toLowerCase()));
    }

    return true;
  }

  unregisterByFile(filePath: string): void {
    const normalizedPath = resolve(filePath);
    const ids = this.fileIndex.get(normalizedPath);

    if (ids) {
      ids.forEach(id => {
        const cmd = this.commands.get(id);
        if (cmd) {
          const names = this.getCommandNames(cmd);
          names.forEach(n => this.nameIndex.delete(n.toLowerCase()));
          if (cmd.aliases) {
            cmd.aliases.forEach(a => this.aliasIndex.delete(a.toLowerCase()));
          }
        }
        this.commands.delete(id);
        this.beforeHookIndex.delete(id);
      });
      this.fileIndex.delete(normalizedPath);
    }
  }

  getAll(): CommandOptions[] {
    return Array.from(this.commands.values());
  }

  getAllCategories(): string[] {
    return Array.from(this.categoryIndex.keys());
  }

  getStats() {
    return {
      total: this.commands.size,
      categories: this.categoryIndex.size,
      files: this.fileIndex.size
    };
  }

  private generateId(command: CommandOptions): string {
    const names = this.getCommandNames(command);
    const base = names[0]?.toLowerCase() || 'unknown';
    if (!this.commands.has(base)) return base;
    let i = 1;
    while (this.commands.has(`${base}_${i}`)) i++;
    return `${base}_${i}`;
  }

  private getCommandNames(command: CommandOptions): string[] {
    const names: string[] = [];
    if (command.command) {
      const cmdNames = Array.isArray(command.command) ? command.command : [command.command];
      names.push(...cmdNames);
    }
    if (command.name) names.push(command.name);
    return names;
  }
}

class MiddlewareChain {
  private middlewares: Middleware[] = [];

  use(middleware: Middleware): this {
    this.middlewares.push(middleware);
    return this;
  }

  async run(msg: Message, final: () => Promise<void>): Promise<void> {
    let index = 0;

    const next = async (): Promise<void> => {
      if (index < this.middlewares.length) {
        await this.middlewares[index++](msg, next);
      } else {
        await final();
      }
    };

    await next();
  }

  clear(): void {
    this.middlewares = [];
  }

  get length(): number {
    return this.middlewares.length;
  }
}

class CommandExecutor {
  private cooldownManager: CooldownManager;
  private abortControllers: Map<string, AbortController> = new Map();
  private commandCounter: number = 0;

  constructor(cooldownMaxAge: number = 3600000) {
    this.cooldownManager = new CooldownManager(cooldownMaxAge);
  }

  async execute(cmd: CommandOptions, msg: Message, context: any, bot: any): Promise<boolean> {
    if (!await this.checkConditions(cmd, msg, bot)) {
      return false;
    }

    if (!await this.checkCooldown(cmd, msg, bot)) {
      return false;
    }

    const controller = new AbortController();
    const commandId = `${msg.sender}:${++this.commandCounter}`;
    this.abortControllers.set(commandId, controller);

    try {
      return await commandStorage.run({ msg, context, startTime: Date.now() }, async () => {
        const timeout = setTimeout(() => controller.abort('timeout'), 30000);

        try {
          const ctxWithSignal = {
            ...context,
            signal: controller.signal
          };

          await cmd.execute!(msg, ctxWithSignal, bot);

          if (cmd.cooldown) {
            const key = this.getCooldownKey(msg, cmd);
            this.cooldownManager.set(key);
          }

          return true;
        } finally {
          clearTimeout(timeout);
          this.abortControllers.delete(commandId);
        }
      });
    } catch (error: any) {
      this.abortControllers.delete(commandId);
      if (error.name === 'AbortError') {
        UI.warn(`[${new Date().toLocaleTimeString()}] Command ${msg.command} was aborted: ${error.message}`);
        await cmdControl(bot, msg, 'timeout');
      } else {
        UI.error(`[${new Date().toLocaleTimeString()}] Error executing command ${msg.command}: ${error.message}`);
        await cmdControl(bot, msg, 'error', error);
      }
      return false;
    }
  }

  getCooldownManager(): CooldownManager {
    return this.cooldownManager;
  }

  private async checkConditions(cmd: CommandOptions, msg: Message, bot: any): Promise<boolean> {
    const checks: Array<[boolean | undefined, string, any?]> = [
      [cmd.disabled, 'disabled'],
      [cmd.owner && !msg.isOwner, 'owner'],
      [cmd.group && !msg.isGroup, 'group'],
      [cmd.admin && !msg.isAdmin, 'admin'],
      [cmd.private && msg.isGroup, 'private'],
      [cmd.botAdmin && !msg.isBotAdmin, 'botAdmin'],
    ];

    for (const [failed, type, extra] of checks) {
      if (failed) {
        await cmdControl(bot, msg, type, extra);
        return false;
      }
    }

    return true;
  }

  private async checkCooldown(cmd: CommandOptions, msg: Message, bot: any): Promise<boolean> {
    if (!cmd.cooldown) return true;

    const key = this.getCooldownKey(msg, cmd);
    const remaining = this.cooldownManager.getRemaining(key, cmd.cooldown);

    if (remaining > 0) {
      await cmdControl(bot, msg, 'cooldown', remaining);
      return false;
    }

    return true;
  }

  private getCooldownKey(msg: Message, cmd: CommandOptions): string {
    const cmdName = Array.isArray(cmd.command) ? cmd.command[0] : cmd.command || 'unknown';
    return `${msg.sender}:${cmdName}`;
  }

  abortUserCommands(userId: string): void {
    for (const [id, controller] of this.abortControllers) {
      if (id.startsWith(userId)) {
        controller.abort('user cancelled');
      }
    }
  }

  destroy(): void {
    this.cooldownManager.destroy();
    this.abortControllers.forEach(controller => controller.abort('system shutdown'));
    this.abortControllers.clear();
  }
}

class CommandFileWatcher {
  private watcher: FSWatcher | null = null;
  private watchedPath: string = '';
  private onFileChange: (path: string, event: 'add' | 'change' | 'unlink') => void;

  constructor(onFileChange: (path: string, event: 'add' | 'change' | 'unlink') => void) {
    this.onFileChange = onFileChange;
  }

  start(commandsPath: string): void {
    this.stop();

    const absolutePath = this.resolvePath(commandsPath);
    this.watchedPath = absolutePath;

    if (!existsSync(absolutePath)) {
      UI.error(`[${new Date().toLocaleTimeString()}] Path does not exist: ${absolutePath}`);
      return;
    }

    const watchConfig = this.getWatchConfig();

    this.watcher = watch(absolutePath, {
      ignored: [/(^|[\/\\])\../, /node_modules/, /\.git/],
      persistent: true,
      ignoreInitial: true,
      depth: 99,
      ...watchConfig
    });

    this.setupWatcherEvents();
  }

  stop(): void {
    if (this.watcher) {
      this.watcher.close();
      this.watcher = null;
      UI.info('🛑 Watcher stopped');
    }
  }

  private resolvePath(givenPath: string): string {
    if (isAbsolute(givenPath)) return givenPath;

    const candidates = [
      resolve(process.cwd(), givenPath),
      resolve(__dirname, givenPath),
      resolve(process.cwd(), 'node_modules', givenPath)
    ];

    for (const path of candidates) {
      if (existsSync(path)) return path;
    }

    return resolve(process.cwd(), givenPath);
  }

  private getWatchConfig() {
    const platform = process.platform;
    const isAndroid = platform === 'android' || !!(process as any).env.TERMUX_VERSION;
    const isWindows = platform === 'win32';

    if (isAndroid || isWindows) {
      return {
        usePolling: true,
        interval: isAndroid ? 1500 : 500,
        binaryInterval: isAndroid ? 2000 : 1000
      };
    }

    return { usePolling: false };
  }

  private setupWatcherEvents(): void {
    if (!this.watcher) return;

    this.watcher
      .on('ready', () => UI.done('Watcher ready'))
      .on('add', path => this.handleFileEvent(path, 'add'))
      .on('change', path => this.handleFileEvent(path, 'change'))
      .on('unlink', path => this.handleFileEvent(path, 'unlink'))
      .on('error', (error: any) => UI.error(`[${new Date().toLocaleTimeString()}] Watcher error: ${error.message}`));
  }

  private handleFileEvent(path: string, event: 'add' | 'change' | 'unlink'): void {
    if (!this.isCommandFile(path)) return;

    const icons: Record<string, string> = { add: '📥', change: '🔄', unlink: '🗑️' };
    UI.info(`[${new Date().toLocaleTimeString()}] ${event.toUpperCase()}: ${this.getRelativePath(path)} ${icons[event]}`);

    this.onFileChange(path, event);
  }

  private isCommandFile(filePath: string): boolean {
    const ext = filePath.split('.').pop()?.toLowerCase();
    return VALID_EXTENSIONS.includes(ext || '');
  }

  private getRelativePath(filePath: string): string {
    try {
      return relative(this.watchedPath, filePath);
    } catch {
      return filePath;
    }
  }
}

class CommandLoader {
  private require = createRequire(import.meta.url);
  private readonly fsModule = import('fs/promises').then(m => m);
  private readonly pathModule = import('path').then(m => m);

  async loadFile(filePath: string): Promise<CommandModule | null> {
    try {
      const normalizedPath = resolve(filePath);
      const isESM = await this.isESMFile(normalizedPath);

      const exported = await this.importModule(normalizedPath, isESM);
      return this.normalizeExports(exported, normalizedPath);
    } catch (error: any) {
      UI.error(`[${new Date().toLocaleTimeString()}] Failed to load ${filePath}: ${error.message}`);
      return null;
    }
  }

  private async importModule(filePath: string, isESM: boolean): Promise<any> {
    if (isESM) {
      const fileUrl = pathToFileURL(filePath).href;
      const module = await import(`${fileUrl}?t=${Date.now()}`);
      return module.default ?? module;
    } else {
      try {
        const resolvedPath = this.require.resolve(filePath);
        delete this.require.cache[resolvedPath];
        return this.require(resolvedPath);
      } catch {
        const fileUrl = pathToFileURL(filePath).href;
        const module = await import(`${fileUrl}?t=${Date.now()}`);
        return module.default ?? module;
      }
    }
  }

  private async isESMFile(filePath: string): Promise<boolean> {
    const ext = filePath.split('.').pop()?.toLowerCase();

    if (ext === 'mjs') return true;
    if (ext === 'cjs') return false;

    if (ext === 'js' || ext === 'ts') {
      return await this.checkPackageJSON(filePath);
    }

    return true;
  }

  private async checkPackageJSON(filePath: string): Promise<boolean> {
    try {
      const fs = await this.fsModule;
      const path = await this.pathModule;

      let dir = path.dirname(filePath);
      const root = path.parse(dir).root;

      while (dir !== root) {
        const pkgPath = path.join(dir, 'package.json');
        try {
          const content = await fs.readFile(pkgPath, 'utf8');
          const pkg = JSON.parse(content);
          return pkg.type === 'module';
        } catch {
          dir = path.dirname(dir);
        }
      }
    } catch {}

    return true;
  }

  private normalizeExports(exported: any, filePath: string): CommandModule | null {
    if (!exported) return null;

    if (Array.isArray(exported)) {
      return exported
        .map(item => this.normalizeExports(item, filePath))
        .filter(Boolean) as CommandOptions[];
    }

    if (typeof exported === 'function') {
      return this.normalizeFunction(exported, filePath);
    }

    if (typeof exported === 'object') {
      return this.normalizeObject(exported, filePath);
    }

    return null;
  }

  private normalizeFunction(fn: any, filePath: string): CommandModule {
    if (fn.name === 'before' || fn.name === 'after' || fn.toString().includes('function before')) {
      return Object.assign(fn, { __filePath: filePath });
    }

    const cmd: CommandOptions = { execute: fn };

    ALL_PROPS.forEach((prop: any) => {
      if (fn[prop] !== undefined) {
        (cmd as any)[prop] = fn[prop];
      }
    });

    Object.keys(fn).forEach(key => {
      if (!ALL_PROPS.includes(key as any) && key !== 'execute') {
        (cmd as any)[key] = fn[key];
      }
    });

    return Object.assign(cmd, { __filePath: filePath });
  }

  private normalizeObject(obj: any, filePath: string): CommandModule | null {
    if (obj.default) {
      return this.normalizeExports(obj.default, filePath);
    }

    if (obj.execute && typeof obj.execute === 'function') {
      return this.attachFilePath(obj, filePath);
    }

    const functionKeys = Object.keys(obj).filter((key: string) =>
      typeof obj[key] === 'function' &&
      !['constructor', 'toString', 'valueOf'].includes(key)
    );

    if (functionKeys.length === 1) {
      const executeFn = obj[functionKeys[0]];
      const cmd = { ...obj, execute: executeFn };
      delete cmd[functionKeys[0]];
      return this.attachFilePath(cmd, filePath);
    }

    return null;
  }

  private attachFilePath(obj: any, filePath: string): any {
    obj.__filePath = filePath;
    return obj;
  }
}

export class CommandSystem {
  private registry: CommandRegistry;
  private middleware: MiddlewareChain;
  private executor: CommandExecutor;
  private loader: CommandLoader;
  private watcher: CommandFileWatcher;
  private beforeHandlers: Handler[] = [];
  private afterHandlers: Handler[] = [];
  private bot: any;
  private loadedPaths: Set<string> = new Set();

  constructor(bot?: any) {
    this.bot = bot;
    this.registry = new CommandRegistry();
    this.middleware = new MiddlewareChain();
    this.executor = new CommandExecutor();
    this.loader = new CommandLoader();
    this.watcher = new CommandFileWatcher(this.handleFileChange.bind(this));
  }

  setBot(bot: any): void {
    this.bot = bot;
  }

  register(command: CommandOptions | Function): void {
    let cmdObj: CommandOptions;

    if (typeof command === 'function') {
      cmdObj = { execute: command as any };
      ALL_PROPS.forEach((prop: any) => {
        if ((command as any)[prop] !== undefined) {
          (cmdObj as any)[prop] = (command as any)[prop];
        }
      });
    } else {
      cmdObj = { ...command };
    }

    this.registry.register(cmdObj, (cmdObj as any).__filePath);
  }

  unregister(commandName: string): boolean {
    return this.registry.unregister(commandName);
  }

  before(handler: Handler): void {
    this.beforeHandlers.push(handler);
  }

  after(handler: Handler): void {
    this.afterHandlers.push(handler);
  }

  use(middleware: Middleware): void {
    this.middleware.use(middleware);
  }

  findCommand(name: string): CommandOptions | undefined {
    return this.registry.findByName(name);
  }

  getCommandsByCategory(category?: string): CommandOptions[] {
    return category ? this.registry.findByCategory(category) : this.registry.getAll();
  }

  getAllCategories(): string[] {
    return this.registry.getAllCategories();
  }

  getAll(): CommandOptions[] {
    return this.registry.getAll();
  }

  async processMessage(msg: Message, ctx: any, config: any): Promise<boolean> {
    if (!msg.body) return false;

    const context: any = {
      conn: ctx.sock,
      text: msg.body,
      args: [],
      command: '',
      prefix: '',
      bot: ctx,
      scrapy: ctx.scrapy
    };

    if (await this.runBeforeHandlers(msg, context)) {
      return true;
    }

    for (const cmd of this.registry.getCommandsWithBeforeHooks()) {
      try {
        const result = await (cmd.before as any)(msg, context, this.bot);
        if (result === true) return true;
      } catch (error: any) {
        UI.error(`Error in command before handler: ${error.message}`);
      }
    }

    const text = msg.body.trim();
    const prefixes = config || ["."];
    const extracted = extractPrefix(text, prefixes);

    if (extracted) {
      const cmd = this.registry.findByName(extracted.command);
      if (!cmd?.execute) return false;

      const cmdContext: any = {
        ...context,
        text: extracted.args.join(' '),
        args: extracted.args,
        command: extracted.command,
        prefix: extracted.prefix
      };

      let executed = false;

      await this.middleware.run(msg, async () => {
        executed = await this.executor.execute(cmd, msg, cmdContext, this.bot);
      });

      if (executed) {
        if (cmd.after) {
          try { await (cmd.after as any)(msg, cmdContext, this.bot); }
          catch (error: any) { UI.error(`Error in command after handler: ${error.message}`); }
        }

        await this.runAfterHandlers(msg, extracted, cmdContext);
      }

      return executed;
    }

    const args = text.split(/\s+/);
    const cmdName = args[0]?.toLowerCase() || '';

    for (const cmd of this.registry.getAll()) {
      if (cmd.usePrefix === false && cmd.execute) {
        if (this.getCommandNames(cmd).includes(cmdName)) {
          const cmdContext: any = {
            ...context,
            text: args.slice(1).join(' '),
            args: args.slice(1),
            command: cmdName,
            prefix: ''
          };

          return await this.executor.execute(cmd, msg, cmdContext, this.bot);
        }
      }
    }

    return false;
  }

  private async runBeforeHandlers(msg: Message, context: any): Promise<boolean> {
    for (const handler of this.beforeHandlers) {
      try {
        const result = await handler(msg, context, this.bot);
        if (result === true) return true;
      } catch (error: any) {
        UI.error(`Error in before handler: ${error.message}`);
      }
    }
    return false;
  }

  private async runAfterHandlers(msg: Message, extracted: any, context: any): Promise<void> {
    for (const handler of this.afterHandlers) {
      try {
        await handler(msg, { command: extracted.command, args: extracted.args, cmdContext: context }, this.bot);
      } catch (error: any) {
        UI.error(`Error in after handler: ${error.message}`);
      }
    }
  }

  private getCommandNames(cmd: CommandOptions): string[] {
    const names: string[] = [];
    if (cmd.command) {
      const cmdNames = Array.isArray(cmd.command) ? cmd.command : [cmd.command];
      names.push(...cmdNames);
    }
    if (cmd.name) names.push(cmd.name);
    if (cmd.aliases) names.push(...cmd.aliases);
    return names.map(n => n.toLowerCase());
  }

  async loadFile(filePath: string): Promise<void> {
    const normalizedPath = resolve(filePath);
    
    if (this.loadedPaths.has(normalizedPath)) {
      UI.warn(`[${new Date().toLocaleTimeString()}] File already loaded, skipping: ${normalizedPath}`);
      return;
    }

    const commands = await this.loader.loadFile(normalizedPath);

    if (!commands) return;

    const cmdArray = Array.isArray(commands) ? commands : [commands];

    for (const cmd of cmdArray) {
      if (typeof cmd === 'function') {
        (cmd as any).__filePath = normalizedPath;
        this.before(cmd as Handler);
      } else if (cmd && (cmd as CommandOptions).execute) {
        (cmd as any).__filePath = normalizedPath;
        this.register(cmd as CommandOptions);
      }
    }

    this.loadedPaths.add(normalizedPath);
  }

  async loadDirectory(commandsPath: string): Promise<void> {
    const absolutePath = this.resolvePath(commandsPath);
    
    if (this.loadedPaths.has(absolutePath)) {
      UI.warn(`[${new Date().toLocaleTimeString()}] Path already loaded, skipping: ${absolutePath}`);
      return;
    }

    const scanDir = async (dir: string): Promise<void> => {
      try {
        const items = await readdir(dir, { withFileTypes: true });

        for (const item of items) {
          const fullPath = join(dir, item.name);

          if (item.isDirectory()) {
            await scanDir(fullPath);
          } else if (item.isFile()) {
            const ext = item.name.split('.').pop()?.toLowerCase();
            if (ext && VALID_EXTENSIONS.includes(ext)) {
              await this.loadFile(fullPath);
            }
          }
        }
      } catch (error: any) {
        UI.error(`Failed to scan ${dir}: ${error.message}`);
      }
    };

    await scanDir(absolutePath);
    this.loadedPaths.add(absolutePath);
  }

  startWatching(commandsPath: string): void {
    this.watcher.start(commandsPath);
  }

  stopWatcher(): void {
    this.watcher.stop();
  }

  private async handleFileChange(filePath: string, event: 'add' | 'change' | 'unlink'): Promise<void> {
    switch (event) {
      case 'add':
      case 'change':
        await new Promise(resolve => setTimeout(resolve, 500));
        await this.reloadFile(filePath);
        break;
      case 'unlink':
        this.unloadFile(filePath);
        break;
    }
  }

  private async reloadFile(filePath: string): Promise<void> {
    this.unloadFile(filePath);
    await this.loadFile(filePath);
  }

  private unloadFile(filePath: string): void {
    const normalizedPath = resolve(filePath);
    this.registry.unregisterByFile(normalizedPath);
    this.loadedPaths.delete(normalizedPath);

    this.beforeHandlers = this.beforeHandlers.filter(handler => {
      const handlerPath = (handler as any).__filePath;
      return !handlerPath || resolve(handlerPath) !== normalizedPath;
    });
  }

  private resolvePath(givenPath: string): string {
    if (isAbsolute(givenPath)) return givenPath;

    const candidates = [
      resolve(process.cwd(), givenPath),
      resolve(__dirname, givenPath)
    ];

    for (const path of candidates) {
      if (existsSync(path)) return path;
    }

    return resolve(process.cwd(), givenPath);
  }

  clearCooldowns(userId?: string): void {
    const cm = this.executor.getCooldownManager();
    cm.clear(userId);
  }

  getStats() {
    return {
      ...this.registry.getStats(),
      middlewares: this.middleware.length,
      beforeHandlers: this.beforeHandlers.length,
      afterHandlers: this.afterHandlers.length
    };
  }

  abortUserCommands(userId: string): void {
    this.executor.abortUserCommands(userId);
  }

  destroy(): void {
    this.stopWatcher();
    this.executor.destroy();
    this.middleware.clear();
    this.beforeHandlers = [];
    this.afterHandlers = [];
    this.loadedPaths.clear();
  }

  resetLoadedPaths(): void {
    this.loadedPaths.clear();
  }
}

export async function loadCommandsFromPath(
  commandsPath: string,
  commandSystem?: CommandSystem
): Promise<CommandOptions[]> {
  if (!commandSystem) return [];

  await commandSystem.loadDirectory(commandsPath);
  commandSystem.startWatching(commandsPath);

  return commandSystem.getAll();
}

export function getCommandContext() {
  return commandStorage.getStore();
}