import { color, rainbow } from "./colors.js";

type UItype = {
  clear: () => void;
  random: (t: string) => void;
  done: (t: string) => void;
  warn: (t: string) => void;
  error: (t: string) => void;
  info: (t: string) => void;
  loading: (t: string) => void;
  line: () => void;
}

const UI: UItype = {
  clear: () => console.clear(),
  random: t => console.log(rainbow(`⌬ ${t} ⌬`)),
  done: t => console.log(color(`✓ ${t}`, "green")),
  warn: t => console.log(color(`! ${t}`, "yellow")),
  error: t => console.log(color(`✗ ${t}`, "red")),
  info: t => console.log(color(`→ ${t}`, "cyan")),
  loading: t => console.log(color(`⚶ ${t} ⚶`, "blue")),
  line: () => console.log(color('--------------------------------------------', "gray"))
}

export { UI }